from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Mock user database
users_db = {
    "user1": {
        "email": "user1@example.com",
        "username": "user1",
        "account_type": "basic",
        "credits": 0,
        "referral_code": None,
        "verified_status": False
    }
}

# Mock authentication function
def authenticate(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        # In a real scenario, this would check the request headers for an auth token
        current_user = request.headers.get('Authorization')
        if not current_user:
            return jsonify({"error": "Authentication required"}), 401
        return func(current_user, *args, **kwargs)
    return wrapper

@app.route('/update_profile', methods=['POST'])
@authenticate
def update_profile(current_user):
    data = request.json
    user = users_db.get(current_user)
    if not user:
        return jsonify({"error": "User not found"}), 404
    
    update_fields = {
        "email": data.get("email"),
        "username": data.get("username"),
        "account_type": data.get("account_type"),
        "credits": data.get("credits"),
        "referral_code": data.get("referral_code"),
        "verified_status": data.get("verified_status")
    }
    
    for field, value in update_fields.items():
        if value is not None:
            user[field] = value
    
    return jsonify({"message": "Profile updated successfully", "user": user}), 200

